INSERT INTO follow_up_day_schedule (
    register_id, department_id, schedule_date, item_type, title, status, created_by
) VALUES (
    #{registerId}, #{departmentId}, #{scheduleDate}, #{itemType}, #{title},
    COALESCE(#{status}, 'planned'), #{createdBy}
)

mapper.update:
UPDATE follow_up_day_schedule
SET status = #{status}
WHERE id = #{id}

mapper.insert:
INSERT INTO follow_up_daily_observation (
    register_id, observation_date, observed_by, note
) VALUES (
    #{registerId}, #{observationDate}, #{observedBy}, #{note}
)

mapper.select:
SELECT
    (
        SELECT COUNT(*)
        FROM follow_up_patient_profile fp

            fp.department_id = #{departmentId}

    ) AS "totalPatients",
    (
        SELECT COUNT(*)
        FROM follow_up_day_schedule s
        WHERE s.schedule_date = #{targetDate}
          AND s.item_type = 'interview'
          AND s.status = 'planned'
          AND s.department_id = #{departmentId}
    ) AS "todayInterviewsPlanned",
    (
        SELECT COUNT(*)
        FROM follow_up_patient_profile fp

            fp.department_id = #{departmentId}

    ) - (
        SELECT COUNT(*)
        FROM follow_up_daily_observation o
        INNER JOIN follow_up_patient_profile fp ON fp.register_id = o.register_id
        WHERE o.observation_date = #{targetDate}
          AND fp.department_id = #{departmentId}
    ) AS "todayObservationPending"
